const items = $input.all();

return items.map(item => {
  const output = {};
  for (const key in item.json) {
    if (item.json[key] !== "" && item.json[key] !== null && item.json[key] !== undefined) {
      output[key] = item.json[key];
    }
  }
  return { json: output };
});

